from flask import Flask, request, redirect, url_for, session
import threading

app = Flask(__name__)
app.secret_key = 'your_secret_key'

# Dummy database
users = {
    'user1': {'password': 'password1', 'mfa_enabled': True},
    'user2': {'password': 'password2', 'mfa_enabled': False}
}

def verify_mfa(username):
    # Simulate MFA verification
    if users[username]['mfa_enabled']:
        print(f"Verifying MFA for {username}...")
        threading.sleep(5)
        return True
    return True

@app.route('/login', methods=['POST'])
def login():
    username = request.form['username']
    password = request.form['password']

    if users.get(username) and users[username]['password'] == password:
        session['username'] = username
        if verify_mfa(username):
            return redirect(url_for('protected'))
        else:
            return "MFA verification failed", 401
    else:
        return "Invalid credentials", 401

@app.route('/verify-mfa')
def protected():
    if 'username' in session:
        return f"Welcome, {session['username']}! Protected resource accessed."
    else:
        return redirect(url_for('login'))

